const sourceItems = $items('Prepare Candidates');
const inputItems = $input.all();

function extractJson(text) {
  const cleaned = String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON object found in draft output');
  return JSON.parse(cleaned.slice(first, last + 1));
}

return inputItems.map((item, idx) => {
  const src = sourceItems[idx]?.json || {};
  const text = item.json?.choices?.[0]?.message?.content || '';
  const draft = extractJson(text);

  return {
    json: {
      ...src,
      draft_raw: text,
      draft_json: draft
    }
  };
});

const sourceItems = $items('Parse Draft JSON');
const inputItems = $input.all();

function extractJson(text) {
  const cleaned = String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON object found in QA output');
  return JSON.parse(cleaned.slice(first, last + 1));
}

function isValidUrl(url) {
  try {
    const urlObj = new URL(url);
    return urlObj.protocol === 'https:';
  } catch {
    return false;
  }
}

function sanitizeRelatedArticles(articles) {
  if (!Array.isArray(articles)) return [];
  return articles
    .filter(article => {
      if (!article || !article.url || !article.title) return false;
      if (!String(article.url).startsWith('https://')) return false;
      if (String(article.title).trim() === '') return false;
      return true;
    })
    .map(article => ({
      title: String(article.title).substring(0, 100),
      url: String(article.url).trim()
    }))
    .filter(article => isValidUrl(article.url))
    .slice(0, 3);
}

function markdownToStyledHtml(md, faq, relatedArticles) {
  if (!md) return '';

  let html = md;

  html = html.replace(/^##\s*(FAQ|Frequently Asked Questions)[\s\S]*?(?=^##[^#]|$)/gmi, '');

  if (faq && Array.isArray(faq)) {
    for (const item of faq) {
      if (item.question) {
        const escapedQ = item.question.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const pattern = new RegExp(`^###\\s*${escapedQ}[\\s\\S]*?(?=^##|^###|$)`, 'gmi');
        html = html.replace(pattern, '');
      }
    }
  }

  html = html.replace(/^###\s*[^\n]*\?\s*\n+[^\n#]+(?:\n[^\n#]+)*/gm, '');

  const codeBlocks = [];
  html = html.replace(/```([\s\S]*?)```/g, (match, content) => {
    codeBlocks.push(content);
    return `___CODEBLOCK_${codeBlocks.length - 1}___`;
  });

  const inlineCodes = [];
  html = html.replace(/`([^`]+)`/g, (match, code) => {
    inlineCodes.push(code);
    return `___INLINECODE_${inlineCodes.length - 1}___`;
  });

  html = html.replace(/^##\s*Related\s*(Guides|guides|Articles|articles).*$/gm, '');
  html = html.replace(/^-\s*(How to|Understanding|Tips for|Guide to).*$/gm, '');
  html = html.replace(/^##\s*Internal\s*Link\s*Suggestions.*$/gm, '');
  html = html.replace(/^##\s*Source\s*Caution\s*Notes.*$/gm, '');
  html = html.replace(/^-\s*Always confirm.*$/gm, '');
  html = html.replace(/^##\s*(Conclusion|In Conclusion|Final Thoughts|Closing Thoughts|Wrapping Up|To Wrap Up|Summary|The Bottom Line|Key Takeaways).*$/gmi, '');

  html = html.replace(/^###\s+(.+)$/gm, '<h3 style="font-size:1.25rem;font-weight:600;color:#374151;margin:1.5rem 0 0.75rem 0;">$1</h3>');
  html = html.replace(/^##\s+(.+)$/gm, '<h2 style="font-size:1.5rem;font-weight:600;color:#1e40af;margin:2rem 0 1rem 0;padding-left:12px;border-left:4px solid #3b82f6;">$1</h2>');
  html = html.replace(/^#\s+(.+)$/gm, '<h1 style="font-size:2rem;font-weight:700;color:#1a1a1a;margin:2rem 0 1rem 0;padding-bottom:0.5rem;border-bottom:3px solid #2563eb;">$1</h1>');

  html = html.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
  html = html.replace(/\*\*(.+?)\*\*/g, '<strong style="color:#1e40af;font-weight:600;">$1</strong>');
  html = html.replace(/(?<!\*)\*([^*]+)\*(?!\*)/g, '<em style="color:#6b7280;font-style:italic;">$1</em>');

  html = html.replace(/___INLINECODE_(\d+)___/g, (match, idx) => {
    return `<code style="background:#f3f4f6;padding:2px 6px;border-radius:4px;font-family:monospace;font-size:0.9rem;">${inlineCodes[parseInt(idx)]}</code>`;
  });

  const lines = html.split('\n');
  const processedLines = [];
  let currentListType = null;
  let listBuffer = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();

    const ulMatch = trimmed.match(/^-\s+(.+)$/);
    const olMatch = trimmed.match(/^(\d+)\.\s+(.+)$/);

    if (ulMatch) {
      if (currentListType === 'ol' && listBuffer.length > 0) {
        processedLines.push(`<ol style="margin:1rem 0 1rem 1.5rem;padding:0;list-style:decimal;">${listBuffer.join('')}</ol>`);
        listBuffer = [];
      }
      currentListType = 'ul';
      listBuffer.push(`<li style="margin:0.5rem 0;padding-left:0.5rem;color:#4b5563;">${ulMatch[1]}</li>`);
    } else if (olMatch) {
      if (currentListType === 'ul' && listBuffer.length > 0) {
        processedLines.push(`<ul style="margin:1rem 0 1rem 1.5rem;padding:0;list-style:disc;">${listBuffer.join('')}</ul>`);
        listBuffer = [];
      }
      currentListType = 'ol';
      listBuffer.push(`<li style="margin:0.5rem 0;padding-left:0.5rem;color:#4b5563;">${olMatch[2]}</li>`);
    } else {
      if (listBuffer.length > 0) {
        if (currentListType === 'ul') {
          processedLines.push(`<ul style="margin:1rem 0 1rem 1.5rem;padding:0;list-style:disc;">${listBuffer.join('')}</ul>`);
        } else if (currentListType === 'ol') {
          processedLines.push(`<ol style="margin:1rem 0 1rem 1.5rem;padding:0;list-style:decimal;">${listBuffer.join('')}</ol>`);
        }
        listBuffer = [];
        currentListType = null;
      }
      processedLines.push(line);
    }
  }

  if (listBuffer.length > 0) {
    if (currentListType === 'ul') {
      processedLines.push(`<ul style="margin:1rem 0 1rem 1.5rem;padding:0;list-style:disc;">${listBuffer.join('')}</ul>`);
    } else if (currentListType === 'ol') {
      processedLines.push(`<ol style="margin:1rem 0 1rem 1.5rem;padding:0;list-style:decimal;">${listBuffer.join('')}</ol>`);
    }
  }

  html = processedLines.join('\n');

  const finalLines = html.split('\n');
  const paragraphProcessed = [];
  let inParagraph = false;

  for (const line of finalLines) {
    const trimmed = line.trim();
    if (!trimmed) {
      if (inParagraph) {
        paragraphProcessed.push('</p>');
        inParagraph = false;
      }
      continue;
    }

    if (trimmed.startsWith('<h') || trimmed.startsWith('<ul') || trimmed.startsWith('<ol') ||
        trimmed.startsWith('<li') || trimmed.startsWith('</') || trimmed.startsWith('<div') ||
        trimmed.startsWith('<pre') || trimmed.startsWith('___CODEBLOCK')) {
      if (inParagraph) {
        paragraphProcessed.push('</p>');
        inParagraph = false;
      }
      paragraphProcessed.push(trimmed);
    } else {
      if (!inParagraph) {
        paragraphProcessed.push('<p style="font-size:1.05rem;color:#4b5563;margin:1rem 0;line-height:1.8;">' + trimmed);
        inParagraph = true;
      } else {
        paragraphProcessed.push('<br>' + trimmed);
      }
    }
  }

  if (inParagraph) {
    paragraphProcessed.push('</p>');
  }

  html = paragraphProcessed.join('\n');

  codeBlocks.forEach((content, i) => {
    html = html.replace(`___CODEBLOCK_${i}___`, `<pre style="background:#f3f4f6;border-radius:8px;padding:1rem;overflow-x:auto;font-family:monospace;font-size:0.9rem;border:1px solid #e5e7eb;"><code>${content}</code></pre>`);
  });

  html = html.replace(/<p style="[^"]*"><\/p>/g, '');
  html = html.replace(/<ul style="[^"]*"><\/ul>/g, '');
  html = html.replace(/<ol style="[^"]*"><\/ol>/g, '');
  html = html.replace(/\n{3,}/g, '\n\n');

  let faqHtml = '';
  if (faq && Array.isArray(faq) && faq.length > 0) {
    faqHtml = `
<div style="margin-top:3rem;padding:2rem;background:linear-gradient(135deg,#f0f9ff 0%,#e0f2fe 100%);border-radius:16px;">
  <h2 style="font-size:1.5rem;font-weight:600;color:#1e40af;margin:0 0 1.5rem 0;padding-left:12px;border-left:4px solid #3b82f6;">Frequently Asked Questions</h2>
  ${faq.map((item) => `
  <div style="background:#fff;border-radius:12px;padding:1.25rem;margin-bottom:1rem;box-shadow:0 2px 8px rgba(0,0,0,0.06);border:1px solid #e0e7ff;">
    <div style="display:flex;align-items:flex-start;gap:12px;font-weight:600;color:#1e40af;margin-bottom:0.75rem;">
      <span style="display:inline-flex;align-items:center;justify-content:center;min-width:28px;height:28px;background:#3b82f6;color:#fff;border-radius:50%;font-weight:700;font-size:0.85rem;">Q</span>
      <span style="flex:1;padding-top:2px;">${item.question || ''}</span>
    </div>
    <div style="display:flex;align-items:flex-start;gap:12px;color:#4b5563;">
      <span style="display:inline-flex;align-items:center;justify-content:center;min-width:28px;height:28px;background:#10b981;color:#fff;border-radius:50%;font-weight:700;font-size:0.85rem;">A</span>
      <span style="flex:1;padding-top:2px;line-height:1.6;">${item.answer || ''}</span>
    </div>
  </div>`).join('')}
</div>`;
  }

  let relatedHtml = '';
  if (relatedArticles && Array.isArray(relatedArticles) && relatedArticles.length > 0) {
    relatedHtml = `
<div style="margin-top:3rem;padding:2rem;background:linear-gradient(135deg,#fef3c7 0%,#fde68a 100%);border-radius:16px;">
  <h2 style="font-size:1.5rem;font-weight:600;color:#92400e;margin:0 0 1.5rem 0;padding-left:12px;border-left:4px solid #f59e0b;">You Might Also Like</h2>
  <div style="display:flex;flex-direction:column;gap:12px;">
    ${relatedArticles.map((article) => `
    <a href="${article.url}" style="display:flex;align-items:center;justify-content:space-between;background:#fff;border-radius:12px;padding:1rem 1.25rem;text-decoration:none;color:#1e40af;font-weight:500;box-shadow:0 2px 8px rgba(0,0,0,0.06);border:1px solid #fcd34d;transition:all 0.2s ease;">
      <span style="flex:1;">${article.title}</span>
      <span style="font-size:1.25rem;color:#f59e0b;font-weight:700;">-></span>
    </a>`).join('')}
  </div>
</div>`;
  }

  const hasOfficialResources = /hikorea|1345|immigration\s*(office|service|contact)/i.test(html);

  let officialResourcesHtml = '';
  if (!hasOfficialResources) {
    officialResourcesHtml = `
<div style="margin-top:3rem;padding:2rem;background:linear-gradient(135deg,#ecfdf5 0%,#d1fae5 100%);border-radius:16px;border:1px solid #6ee7b7;">
  <h2 style="font-size:1.5rem;font-weight:600;color:#065f46;margin:0 0 1rem 0;padding-left:12px;border-left:4px solid #10b981;">Where to Get Official Information</h2>
  <p style="font-size:1.05rem;color:#4b5563;margin:1rem 0;line-height:1.8;">Always verify the latest requirements through official channels before proceeding:</p>
  <ul style="margin:1rem 0 1rem 1.5rem;padding:0;list-style:disc;">
    <li style="margin:0.75rem 0;color:#4b5563;"><strong style="color:#065f46;">HiKorea Portal</strong> (hikorea.go.kr) - The official online platform for visa applications, extensions, and immigration status checks.</li>
    <li style="margin:0.75rem 0;color:#4b5563;"><strong style="color:#065f46;">Immigration Contact Center</strong> - Call 1345 from any phone in Korea. Multilingual support available 24/7.</li>
    <li style="margin:0.75rem 0;color:#4b5563;"><strong style="color:#065f46;">Local Immigration Office</strong> - Visit your nearest immigration office for in-person assistance.</li>
  </ul>
</div>`;
  }

  const currentDate = new Date();
  const lastUpdated = currentDate.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });
  const currentYear = currentDate.getFullYear();

  const metaBlockHtml = `
<div style="background:#f9fafb;border-bottom:1px solid #e5e7eb;padding:1rem;margin-bottom:1.5rem;font-size:0.9rem;color:#6b7280;display:flex;align-items:center;gap:2rem;flex-wrap:wrap;border-radius:8px;">
  <span>Last updated: ${lastUpdated}</span>
  <span style="color:#059669;">Information verified for ${currentYear}</span>
</div>`;

  const finalHtml = `<div style="font-family:'Pretendard',-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;line-height:1.8;color:#333;max-width:100%;">
${metaBlockHtml}
${html}
${officialResourcesHtml}
${faqHtml}
${relatedHtml}
</div>`;

  return finalHtml;
}

return inputItems.map((item, idx) => {
  const src = sourceItems[idx]?.json || {};
  const text = item.json?.choices?.[0]?.message?.content || '';
  const qa = extractJson(text);

  const rawScore = Number(qa.overall_score || 0);
  const score = rawScore <= 10 ? rawScore * 10 : rawScore;
  const decision = String(qa.decision || '').toLowerCase().trim();

  const shouldSave = (decision === 'approve') || (decision === 'revise' && score >= 60);

  const relatedArticles = sanitizeRelatedArticles(src.related_articles);

  let cleanTitle = qa.final_title || '';
  cleanTitle = cleanTitle.replace(/[:*#|\[\]"'\-\u2013\u2014]/g, '').replace(/\s+/g, ' ').trim();

  const bodyHtml = markdownToStyledHtml(qa.final_body_markdown || '', qa.final_faq || [], relatedArticles);

  return {
    json: {
      ...src,
      qa_raw: text,
      qa_json: qa,
      should_save: shouldSave,
      final_title: cleanTitle,
      final_slug: qa.final_slug,
      final_meta_description: qa.final_meta_description,
      final_excerpt: qa.final_excerpt,
      final_body_markdown: qa.final_body_markdown,
      final_body_html: bodyHtml,
      final_faq: qa.final_faq,
      final_internal_link_suggestions: qa.final_internal_link_suggestions,
      qa_decision: qa.decision,
      qa_score: qa.overall_score
    }
  };
});

const wpResponse = $json;
const itemIndex = $itemIndex;

const originalData = $items('IF Should Save')[itemIndex]?.json || {};

return {
  json: {
    ...originalData,
    wp_id: wpResponse.id,
    wp_link: wpResponse.link,
    wp_guid: wpResponse.guid?.rendered || '',
    wp_status: wpResponse.status,
    wp_slug: wpResponse.slug
  }
};

const now = new Date().toISOString();

const rowNumber = $json.row_number;
if (rowNumber === undefined || rowNumber === null || rowNumber === '') {
  throw new Error(`Invalid row_number: ${rowNumber}. Data flow issue detected.`);
}

return {
  row_number: rowNumber,
  topic_id: $json.topic_id || '',
  status: 'published',
  retry_count: Number($json.retry_count || 0),
  qa_score: Number($json.qa_score || 0),
  qa_decision: $json.qa_decision || 'approve',
  published_url: $json.wp_link || $json.wp_guid || '',
  last_error: '',
  next_retry_at: '',
  note: `${$json.note || ''} | published`
};

const rowNumber = $json.row_number;
if (rowNumber === undefined || rowNumber === null || rowNumber === '') {
  throw new Error(`Build Fail Update: row_number is missing. Available keys: ${Object.keys($json).join(', ')}`);
}

const retryCount = Number($json.retry_count || 0) + 1;
const qaDecision = $json.qa_decision || 'reject';
const qaScore = Number($json.qa_score || 0);
const now = new Date().toISOString();

const nextStatus = retryCount >= 3 ? 'blocked' : 'queued';

return {
  row_number: rowNumber,
  topic_id: $json.topic_id || '',
  status: nextStatus,
  retry_count: retryCount,
  qa_score: qaScore,
  qa_decision: qaDecision,
  last_error: `QA gate failed: decision=${qaDecision}, score=${qaScore}`,
  next_retry_at: nextStatus === 'queued' ? now : '',
  note: `${$json.note || ''} | auto-fail handled`,
  seed_keyword: $json.seed_keyword || '',
  category: $json.category || '',
  subcategory: $json.subcategory || ''
};

